import Mathlib.Tactic.Classical
import Mathlib.Tactic.Core
import Mathlib.Tactic.Int.Basic
import Mathlib.Tactic.Nonclassical

open Nat
open Function
open Lean
open Lean.Elab.Tactics
open Lean.Parser.Tactics

#define loop_rec (a b : Nat) : Nat :=
if a > b then
  let new_b := b + a
  let new_a := a + 1
  loop_rec new_a new_b
else
  a

#define random_neg (): Nat :=
if RandomIO.nextInt 0 < 50 then -(RandomIO.nextInt 0) else RandomIO.nextInt 0

#define main_func : IO Unit := do
  let x ← random_neg
  let y ← random_neg
  loop x y

#define init_main : IO Unit := do
  RandomIO.setSeed <| Random.getTime
  main_func

#define loop_func (a b : Nat) : IO Unit := do
  if a > b then do
    let mut new_b := b
    let mut new_a := a
    loop_func new_a (new_b + new_a)
  else pure unit

#define check_property : IO Unit := do
  let result ← init_main
