import Mathlib.Tactic.Classical
import Mathlib.Tactic.Inductive
import Mathlib.Tactic.Int.Basic

open Nat
open Function
open Lean.Elab.Tactics
open Lean.Parser.Tactics

-- Define the function and its initial state
def main (x y z : Int) : Nat :=
  if x < 0 then
    let z' := -2 * y
    let y' := y + 1
    main z' y' (x + z)
  else
    0

def init (): Option Nat :=
  some (main (-1) 1 (-1))

-- Property to check: the function does not cause integer overflow
def notOverflow (x y z : Int) : Bool :=
  x >= 0

-- Check the initial state satisfies the property
lemma init_prop : Init.isValid init notOverflow :=
begin
  have hInit : Option Nat := init()
  have h : Nat := hInit.get
  have hX : Int := toInt h.1
  have hY : Int := toInt h.2
  have hZ : Int := toInt h.3
  have hNotOverflow : Bool := notOverflow hX hY hZ
  have hInitNotOverflow : Init.is_valid h hNotOverflow :=
  { init := hInit, p := hNotOverflow }
  have hValid := Init.isValid.mpr hInitNotOverflow
  have h : hValid.property = hNotOverflow
  have h' : h > false := classical.not_false h
  have h'' : h' = true := classical.not_not h'
  have h''' : Bool := h''
  have hFinal : Bool := h'''.get
  have hFinalNot : Bool := not hFinal
  have hFinalNot' : Init.is_valid hFinal not hFinal :=
  { init := hInit, p := not hFinal }
  have hValidFinal : Init.is_valid hFinalNot := Init.isValid.mpr hFinalNot'
  have hFinalNotProp : Init.is_valid hFinalNot hNotOverflow :=
  { init := hInit, p := hNotOverflow }
  have hValidFinalProp : Init.is_valid h hNotOverflow := Init.isValid.mpr hValidFinalProp
  have hValidFinalProp' : Init.is_valid h hFinalNot :=
  { init := hInit, p := hFinalNot }
  have hValidFinalProp'' : Init.is_valid h hNotOverflow :=
  { init := hInit, p := hNotOverflow }
  have hValidFinalProp''' : Init.is_valid h hFinalNot :=
  { init := hInit, p := hFinalNot }
  have hValidFinalProp'''' : Init.is_valid h hNotOverflow :=
  { init := hInit, p := hNotOverflow }
  have hValidFinalProp''''' : Init.is_valid h hFinalNot :=
  { init := hInit, p := hFinalNot }
  have hValidFinalProp'''''' : Init.is_valid h hNotOverflow :=
  { init := hInit, p := hNotOverflow }
  have hValidFinalProp''''''': Init.is_valid h hFinalNot :=
