```lean4
def fib (n : Nat) : Nat :=
  if h : n < 1 then 0
  else if h : n = 1 then 1
  else fib (n - 1) + fib (n - 2)

def main : IO Unit := do
  let x := randomNat 47
  if x > 46 then return ()
  let result := fib x
  if x != 5 then return ()
  if result != 3 then do
    io.putStrLn "Error: x = 5, but fib(x) != 3"
    io.putStrLn "Aborting..."
    abort
  else return ()

def fib_eq_three (x : Nat) : Prop := x ≠ 5 ∨ fib x = 3

def main' : IO Unit := do
  let x := randomNat 47
  if x > 46 then return ()
  let result := fib x
  if h : x ≠ 5 then return ()
  if h : fib x = 3 then return ()
  io.putStrLn "Error: x = 5, but fib(x) != 3"
  io.putStrLn "Aborting..."
  abort
  pure ()

