 ===BEGIN LEAN PROOF===
#print "Main.lean"

import Mathlib

open Nat Int

-- Define the function main and its precondition and postcondition
def main (k : Int) : Nat :=
  let mut y : Nat := 0
  let mut x : Nat := 0
  let mut c : Nat := 0
  let mut cond : Bool := true

  while cond do
    have h0 : 4 * x - y.nat.val.pow 3 - 2 * y.nat.val.pow 2 - y.nat.val.pow 2 = 0 := by { rfl }
    have h1 : k * y - y.nat.val.pow 2 = 0 := by { rfl }
    have h2 : y.nat.val + 1 < Nat.max := by { rw Nat.max, arith_from_le_of_lt h1.symm }

    set y := y + 1
    set x := x + y.nat.val.pow 3

    have h3 : 4 * x - y.nat.val.pow 3 - 2 * y.nat.val.pow 2 - y.nat.val.pow 2 ≠ 0 := by { rfl }
    have h4 : y.nat.val + 1 < Nat.max := h2

    have h5 : ∥y∥ < ∥k∥ := by { rw Nat.abs_sub, arith_from_le_of_lt h1.symm, arith_from_le_of_lt h4 }

    have h6 : ∥x∥ < ∥k∥ := by { rw Nat.abs_add, arith_from_le_of_lt h1, arith_from_le_of_lt h5, arith_from_le_of_lt h4 }

    have h7 : ∥x∥ + ∥y∥ < ∥k∥ := by { rw Nat.abs_add, arith_from_le_of_lt h5, arith_from_le_of_lt h4 }

    have h8 : ∥x∥ + ∥y∥ ≤ ∥k∥ := by { rw Nat.abs_add, arith_from_le_of_lt h5, arith_from_le_of_lt h4, arith_from_le_of_le h7 h6 }

