import Mathlib.SMT.Solver

open SMT

def main : Unit := do
  let n : nat := ∥∥(int.of_nat <| nat.random 32)∥∥
  let p : nat := 0
  let q : nat := 1
  let r : nat := n
  let h : nat := 0

  let q_pow_2 : expr := (4 * q)
  let q_pow_n : expr := (q_pow_2 ^ nat.of_int (n - 1))

  let cond_1 : expr := (q > n)
  let cond_2 : expr := (q % 4 = 0)
  let cond_3 : expr := (p % 2 = 0)

  let loop : expr := ∥∥(
    let h_new : expr := p + q
    let p_new : expr := p / 2

    let cond_loop : expr := (r < h_new)

    if cond_1 then (
      let h_new_2 : expr := h_new * h_new
      let h_new_3 : expr := h_new_2 * h_new
      let h_new_4 : expr := h_new_3 + h
      let p_new_2 : expr := p_new * p_new
      let p_new_3 : expr := p_new_2 * p_new
      let p_new_4 : expr := p_new_3 + p

      let cond_h : expr := (h_new_4 * h_new_4 - 12 * h_new_4 * n + 16 * n * p_new_4 + 12 * h_new_4 * r - 16 * p_new_4 * r - h_new_4 - 4 * p_new_4 = 0)
      let cond_p : expr := (p_new_2 * p_new_2 - n + r = 0)
      let cond_h_p : expr := (h_new_3 * p_new_2 - 4 * h_new_4 * n + 4 * n * p_new_4 + 4 * h_new_4 * r - 4 * p_new_4 * r - p_new_2 = 0)

      if cond_loop then (
        let r_new : expr := r - h_new
        let p_new_5 : expr := p_new_2 + q
        let p_new_6 : expr := p_new_5 * p_new_5
        let p_new_7 : expr := p_new_6 + p

        let cond_r : expr := (h_new_4 * h_new_4 * h_new_4 - 12 * h_new_4 * n * q_pow_n + 16 * n * p_new_7 * q_pow_n + 12 * h_new_4 * r_new * q_pow_n - 16 * p_new_7 * r_new * q_pow_n - h_new_4 * h_new_4 * r_new + 4 * h_new_4 * p_new_5 * r_new - 8 * n * q_pow_n * r_new + q_pow_n * q_pow_n * r_new + 4 * q_pow_n * r_new * r_new = 0)

        assume cond_r
      )
    )

    return ()
  )

  assume cond_1
  assume cond_2
  assume cond_3

  loop

  assume h_final_sqr : (h * h = n)
  assume p_final_sqr : (p * p = n)

  have h_final_eq_q_pow_n : h = q_pow_n := by rw [h_final_sqr, sqrt_eq_of_pos n]
  have p_final_eq_q_pow_n : p = q_pow_n := by rw [p_final_sqr, sqrt_eq_of_pos n]

  have h_final_even : h % 2 = 0 := by rw [h_final_eq_q_pow_n, pow_two_even]
  have p_final_even : p % 2 = 0 := by rw [p_final_eq_q_pow_n, pow_two_even]

  have h_final_gt_q : h > q := by rw [h_final_eq_q_pow_n, pow_two_gt_one]

  have q_pow_n_gt_n : q_pow_n > n := by rw [h_final_gt_q, pow_two_gt_one]

  have h_final_gt_2_p : h > 2 * p := by rw [h_final_gt_q, pow_two_mul, pow_two_gt_one, pow_two_mul]

  have r_final_lt_h : r < h := by rw [h_final_eq_q_pow_n, pow_two_mul, pow_two_gt_one, pow_two_mul
